type QuestExpansionSeed = {
  slug: string;
  title: string;
  question: string;
  correct: string;
  wrong: [string, string];
  explanation: string;
  appLink: QuestLesson["appLink"];
  column?: string;
  sources?: QuestSource[];
};

function q(
  slug: string,
  title: string,
  question: string,
  correct: string,
  wrong1: string,
  wrong2: string,
  explanation: string,
  appLink: QuestLesson["appLink"],
  column?: string,
  sourcesForLesson?: QuestSource[]
): QuestExpansionSeed {
  return {
    slug,
    title,
    question,
    correct,
    wrong: [wrong1, wrong2],
    explanation,
    appLink,
    column,
    sources: sourcesForLesson
  };
}

